    public PatientSearchResponse SearchPatient(PatientSearchCriteria criteria)
    {
        try
        {
            string userId = GetCurrentUserId();
            string auditId = HipaaAuditLogger.LogAccess("SEARCH_PATIENT", criteria.PatientId ?? "N/A", userId,
                $"Search by: LastName={criteria.LastName}, DOB={criteria.DateOfBirth}");

            var results = new List<PatientRecord>();

            lock (StoreLock)
            {
                foreach (var kvp in PatientStore)
                {
                    var patient = kvp.Value;
                    bool match = true;

                    if (!string.IsNullOrEmpty(criteria.PatientId) && patient.PatientId != criteria.PatientId)
                        match = false;
                    if (!string.IsNullOrEmpty(criteria.LastName) &&
                        !patient.LastName.Equals(criteria.LastName, StringComparison.OrdinalIgnoreCase))
                        match = false;
                    if (criteria.DateOfBirth.HasValue && patient.DateOfBirth.Date != criteria.DateOfBirth.Value.Date)
                        match = false;
                    if (!string.IsNullOrEmpty(criteria.SocialSecurityNumber) &&
                        patient.SocialSecurityNumber != criteria.SocialSecurityNumber)
                        match = false;

                    if (match)
                        results.Add(patient);
                }
            }

            return new PatientSearchResponse
            {
                Success = true,
                Message = $"Found {results.Count} patient(s)",
                TransactionId = Guid.NewGuid().ToString(),
                Timestamp = DateTime.UtcNow,
                AuditTrailId = auditId,
                Patients = results,
                TotalResults = results.Count
            };
