    public ClinicalDocumentResponse GetClinicalDocuments(ClinicalDocumentRequest request)
    {
        try
        {
            if (request == null || string.IsNullOrEmpty(request.PatientId))
                throw new FaultException<HealthcareFault>(
                    CreateFault("INVALID_INPUT", "PatientId is required."),
                    new FaultReason("Invalid input"));

            string userId = GetCurrentUserId();
            string auditId = HipaaAuditLogger.LogAccess("GET_DOCUMENTS", request.PatientId, userId,
                $"RequestedBy={request.RequestingProviderId}, Purpose={request.PurposeOfUse}");

            PatientRecord patient;
            lock (StoreLock)
            {
                if (!PatientStore.TryGetValue(request.PatientId, out patient))
                {
                    throw new FaultException<HealthcareFault>(
                        CreateFault("PATIENT_NOT_FOUND", $"Patient with ID {request.PatientId} not found."),
                        new FaultReason("Patient not found"));
                }
            }

            var documents = new List<MedicalRecord>();
            if (patient.MedicalHistory != null)
            {
                foreach (var record in patient.MedicalHistory)
                {
                    bool include = true;

                    if (!string.IsNullOrEmpty(request.DocumentType))
                    {
                        RecordType requestedType;
                        if (Enum.TryParse(request.DocumentType, true, out requestedType))
                        {
                            if (record.Type != requestedType) include = false;
                        }
                    }

                    if (request.FromDate.HasValue && record.Date < request.FromDate.Value)
                        include = false;
                    if (request.ToDate.HasValue && record.Date > request.ToDate.Value)
                        include = false;

                    if (include)
                        documents.Add(record);
                }
            }

            return new ClinicalDocumentResponse
            {
                Success = true,
                Message = $"Retrieved {documents.Count} clinical document(s)",
                TransactionId = Guid.NewGuid().ToString(),
                Timestamp = DateTime.UtcNow,
                AuditTrailId = auditId,
                Documents = documents
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            HipaaAuditLogger.LogSecurityEvent("GET_DOCUMENTS_ERROR", ex.Message);
            throw new FaultException<HealthcareFault>(
                CreateFault("DOC_ERR", "An error occurred while retrieving clinical documents."),
                new FaultReason("Document retrieval failed"));
        }
    }

