        try
        {
            if (string.IsNullOrEmpty(patientId) || fullRecord == null)
                throw new FaultException<HealthcareFault>(
                    CreateFault("INVALID_INPUT", "PatientId and full record are required."),
                    new FaultReason("Invalid input"));

            string userId = GetCurrentUserId();
            string auditId = HipaaAuditLogger.LogAccess("SUBMIT_CCD", patientId, userId,
                "Continuity of Care Document submitted");

            fullRecord.PatientId = patientId;

            lock (StoreLock)
            {
                if (PatientStore.ContainsKey(patientId))
                {
                    // Merge records
                    var existing = PatientStore[patientId];

                    if (fullRecord.MedicalHistory != null)
                    {
                        if (existing.MedicalHistory == null)
                            existing.MedicalHistory = new List<MedicalRecord>();
                        existing.MedicalHistory.AddRange(fullRecord.MedicalHistory);
                    }

                    if (fullRecord.CurrentMedications != null)
                    {
                        if (existing.CurrentMedications == null)
                            existing.CurrentMedications = new List<Medication>();
                        existing.CurrentMedications.AddRange(fullRecord.CurrentMedications);
                    }

                    if (fullRecord.Allergies != null)
                    {
                        if (existing.Allergies == null)
                            existing.Allergies = new List<Allergy>();
                        existing.Allergies.AddRange(fullRecord.Allergies);
                    }

                    // Update demographics if provided
                    if (!string.IsNullOrEmpty(fullRecord.FirstName)) existing.FirstName = fullRecord.FirstName;
                    if (!string.IsNullOrEmpty(fullRecord.LastName)) existing.LastName = fullRecord.LastName;
                    if (fullRecord.Contact != null) existing.Contact = fullRecord.Contact;
                    if (fullRecord.Insurance != null) existing.Insurance = fullRecord.Insurance;
