            throw new FaultException<HealthcareFault>(
                CreateFault("CCD_ERR", "An error occurred while processing the Continuity of Care Document."),
                new FaultReason("CCD processing failed"));
        }
    }
}

// ============ Custom Security Configuration ============

public static class HealthcareSecurityBindingFactory
{
    /// <summary>
    /// Creates a WS-Security compliant binding with mutual certificate authentication,
    /// AES-256 encryption, and SHA-256 signatures for HIPAA compliance.
    /// </summary>
    public static CustomBinding CreateHipaaCompliantBinding()
    {
        // Create symmetric security binding element with X.509 tokens
        var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
            MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

        // Configure algorithm suite for HIPAA-grade encryption
        // Basic256Sha256 uses AES-256 for encryption and SHA-256 for signatures
        securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        // Enable secure session for conversation security
        securityElement.IncludeTimestamp = true;
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

        // Set message protection order
        securityElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

        // Enable derived keys for additional security
        securityElement.SetKeyDerivation(true);

        // Configure key wrap algorithm
        securityElement.KeyEntropyMode = SecurityKeyEntropyMode.CombinedEntropy;

        // Build the custom binding
        var binding = new CustomBinding();
        binding.Elements.Add(securityElement);

        // Add reliable session for message delivery guarantee
        var reliableSession = new ReliableSessionBindingElement
        {
            Ordered = true,
            InactivityTimeout = TimeSpan.FromMinutes(10),
            MaxRetryCount = 3
        };
        binding.Elements.Add(reliableSession);

        // Text message encoding for SOAP 1.2 with UTF-8
        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10,
            WriteEncoding = System.Text.Encoding.UTF8
        };
        textEncoding.ReaderQuotas.MaxStringContentLength = 1048576; // 1MB
        textEncoding.ReaderQuotas.MaxArrayLength = 1048576;
        textEncoding.ReaderQuotas.MaxDepth = 64;
        binding.Elements.Add(textEncoding);

        // HTTPS transport for transport-level encryption (defense in depth)
        var httpsTransport = new HttpsTransportBindingElement
        {
            RequireClientCertificate = true,
            MaxReceivedMessageSize = 10485760, // 10MB
            MaxBufferSize = 10485760,
            AuthenticationScheme = System.Net.AuthenticationSchemes.Anonymous
        };
        binding.Elements.Add(httpsTransport);

        binding.SendTimeout = TimeSpan.FromMinutes(5);
        binding.ReceiveTimeout = TimeSpan.FromMinutes(5);
        binding.OpenTimeout = TimeSpan.FromMinutes(1);
        binding.CloseTimeout = TimeSpan.FromMinutes(1);

        return binding;
    }

    /// <summary>
    /// Creates a simpler message-security binding using username/password + certificate
    /// for environments where mutual certificate auth is not available.
    /// </summary>
    public static CustomBinding CreateUsernameOverCertificateBinding()
    {
        var securityElement = SecurityBindingElement.CreateUserNameOverTransportBindingElement();
        securityElement.IncludeTimestamp = true;
        securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

        var binding = new CustomBinding();
        binding.Elements.Add(securityElement);

        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10,
            WriteEncoding = System.Text.Encoding.UTF8
        };
        binding.Elements.Add(textEncoding);

        var httpsTransport = new HttpsTransportBindingElement
        {
            MaxReceivedMessageSize = 10485760
        };
        binding.Elements.Add(httpsTransport);

        return binding;
    }

    /// <summary>
    /// Creates a WSHttpBinding with message security for simpler deployments.
    /// </summary>
    public static WSHttpBinding CreateWsHttpSecureBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
        {
            MaxReceivedMessageSize = 10485760,
            MaxBufferPoolSize = 10485760
        };

        binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
        binding.Security.Message.EstablishSecurityContext = true;
        binding.Security.Message.NegotiateServiceCredential = false;
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;

        binding.ReaderQuotas.MaxStringContentLength = 1048576;
        binding.ReaderQuotas.MaxArrayLength = 1048576;
        binding.ReaderQuotas.MaxDepth = 64;

        return binding;
    }
}

// ============ Service Host Configuration ============

public class HealthcareServiceHostFactory
{
    public static ServiceHost CreateSecureServiceHost(
        string baseAddress,
        string serviceCertThumbprint,
        StoreLocation certStoreLocation = StoreLocation.LocalMachine)
    {
        var host = new ServiceHost(typeof(HealthcareRecordService), new Uri(baseAddress));

        // Add service endpoint with HIPAA-compliant binding
        var binding = HealthcareSecurityBindingFactory.CreateHipaaCompliantBinding();
        var endpoint = host.AddServiceEndpoint(typeof(IHealthcareRecordService), binding, "secure");

        // Configure service certificate
        host.Credentials.ServiceCertificate.SetCertificate(
            certStoreLocation,
            StoreName.My,
            X509FindType.FindByThumbprint,
            serviceCertThumbprint);

        // Configure client certificate validation
        host.Credentials.ClientCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        host.Credentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;

        // Service metadata behavior (disable in production for security)
        var smb = host.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (smb == null)
        {
            smb = new ServiceMetadataBehavior
            {
                HttpsGetEnabled = true,
                HttpGetEnabled = false // Disable non-secure metadata
            };
            host.Description.Behaviors.Add(smb);
        }

        // Service debug behavior
        var sdb = host.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (sdb == null)
        {
            sdb = new ServiceDebugBehavior { IncludeExceptionDetailInFaults = false };
            host.Description.Behaviors.Add(sdb);
        }
        else
        {
            sdb.IncludeExceptionDetailInFaults = false;
        }

        // Configure throttling
        var throttle = host.Description.Behaviors.Find<ServiceThrottlingBehavior>();
        if (throttle == null)
        {
            throttle = new ServiceThrottlingBehavior
            {
                MaxConcurrentCalls = 100,
                MaxConcurrentInstances = 100,
                MaxConcurrentSessions = 100
            };
            host.Description.Behaviors.Add(throttle);
        }

        return host;
    }

    /// <summary>
    /// Creates a development service host that uses WSHttpBinding with message security
    /// for easier local testing while still maintaining encryption.
    /// </summary>
    public static ServiceHost CreateDevelopmentServiceHost(string baseAddress)
    {
        var host = new ServiceHost(typeof(HealthcareRecordService), new Uri(baseAddress));

        var binding = new WSHttpBinding(SecurityMode.Message);
        binding.Security.Message.ClientCredentialType = MessageCredentialType.Windows;
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
        binding.MaxReceivedMessageSize = 10485760;

        host.AddServiceEndpoint(typeof(IHealthcareRecordService), binding, "");

        var smb = new ServiceMetadataBehavior
        {
            HttpGetEnabled = true
        };
        host.Description.Behaviors.Add(smb);

        host.AddServiceEndpoint(
            typeof(IMetadataExchange),
            MetadataExchangeBindings.CreateMexHttpBinding(),
            "mex");

        var sdb = host.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (sdb != null)
            sdb.IncludeExceptionDetailInFaults = true;
        else
            host.Description.Behaviors.Add(new ServiceDebugBehavior { IncludeExceptionDetailInFaults = true });

        return host;
    }
}

// ============ Client Proxy Factory ============

public class HealthcareServiceClientFactory
{
    public static ChannelFactory<IHealthcareRecordService> CreateSecureChannelFactory(
        string endpointAddress,
        string clientCertThumbprint,
        string serviceCertThumbprint,
        StoreLocation certStoreLocation = StoreLocation.LocalMachine)
    {
        var binding = HealthcareSecurityBindingFactory.CreateHipaaCompliantBinding();
        var endpoint = new EndpointAddress(
            new Uri(endpointAddress),
            EndpointIdentity.CreateX509CertificateIdentity(
                FindCertificate(serviceCertThumbprint, certStoreLocation)));

        var factory = new ChannelFactory<IHealthcareRecordService>(binding, endpoint);

        factory.Credentials.ClientCertificate.SetCertificate(
            certStoreLocation,
            StoreName.My,
            X509FindType.FindByThumbprint,
            clientCertThumbprint);

        factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;

        return factory;
    }

    private static X509Certificate2 FindCertificate(string thumbprint, StoreLocation location)
    {
        var store = new X509Store(StoreName.My, location);
        try
        {
            store.Open(OpenFlags.ReadOnly);
            var certs = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, false);
            if (certs.Count == 0)
                throw new InvalidOperationException($"Certificate with thumbprint {thumbprint} not found.");
            return certs[0];
        }
        finally
        {
            store.Close();
        }
    }
}

// ============ Program Entry Point ============

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("=== HIPAA-Compliant Healthcare Records SOAP Service ===");
        Console.WriteLine();

        // Use development mode for demonstration
        string baseAddress = "http://localhost:8443/healthcare";

        ServiceHost host = null;
        try
        {
            host = HealthcareServiceHostFactory.CreateDevelopmentServiceHost(baseAddress);

            host.Opened += (s, e) =>
            {
                Console.WriteLine($"[{DateTime.UtcNow:O}] Service host opened successfully.");
                foreach (var ep in host.Description.Endpoints)
                {
                    Console.WriteLine($"  Endpoint: {ep.Address}");
                    Console.WriteLine($"  Binding: {ep.Binding.Name}");
                    Console.WriteLine($"  Contract: {ep.Contract.Name}");
                    Console.WriteLine();
                }
            };

            host.Open();

            Console.WriteLine();
            Console.WriteLine("Healthcare Record Service is running.");
            Console.WriteLine("WSDL available at: " + baseAddress + "?wsdl");
            Console.WriteLine();

            // Run demo operations
            RunDemoOperations(baseAddress);

            Console.WriteLine();
            Console.WriteLine("Press ENTER to stop the service...");
            Console.ReadLine();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex.Message}");
            if (ex.InnerException != null)
                Console.WriteLine($"Inner: {ex.InnerException.Message}");
        }
        finally
        {
            if (host != null)
            {
                try
                {
                    if (host.State == CommunicationState.Opened)
                        host.Close();
                    else
                        host.Abort();
                }
                catch
                {
                    host.Abort();
                }
            }
        }
    }

    static void RunDemoOperations(string baseAddress)
    {
        Console.WriteLine("--- Running Demo Operations ---");
        Console.WriteLine();

        try
        {
            var binding = new WSHttpBinding(SecurityMode.Message);
            binding.Security.Message.ClientCredentialType = MessageCredentialType.Windows;
            binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
            binding.MaxReceivedMessageSize = 10485760;

            var factory = new ChannelFactory<IHealthcareRecordService>(
                binding,
                new EndpointAddress(baseAddress));

            var client = factory.CreateChannel();

            // 1. Create a patient record
            Console.WriteLine("1. Creating patient record...");
            var patient = new PatientRecord
            {
                FirstName = "Jane",
                LastName = "Doe",
                DateOfBirth = new DateTime(1985, 3, 15),
                SocialSecurityNumber = "123-45-6789",
                Gender = "Female",
                Contact = new ContactInfo
                {
                    Address = "123 Health St",
                    City = "Medical City",
                    State = "CA",
                    ZipCode = "90210",
                    Phone = "555-0100",
                    Email = "jane.doe@email.com",
                    EmergencyContactName = "John Doe",
                    EmergencyContactPhone = "555-0101"
                },
                Insurance = new InsuranceInfo
                {
                    InsuranceProvider = "HealthCare Plus",
                    PolicyNumber = "HCP-2024-001234",
                    GroupNumber = "GRP-5678",
                    SubscriberId = "SUB-001234",
                    EffectiveDate = new DateTime(2024, 1, 1),
                    ExpirationDate = new DateTime(2024, 12, 31)
                },
                Allergies = new List<Allergy>
                {
                    new Allergy
                    {
                        Allergen = "Penicillin",
                        Reaction = "Hives and swelling",
                        Severity = AllergySeverity.Severe,
                        ReportedDate = new DateTime(2020, 6, 1)
                    }
                },
                MedicalHistory = new List<MedicalRecord>(),
                CurrentMedications = new List<Medication>()
            };

            var createResponse = client.CreatePatientRecord(patient);
            Console.WriteLine($"   Result: {createResponse.Message}");
            Console.WriteLine($"   AuditTrail: {createResponse.AuditTrailId}");
            string patientId = createResponse.Message.Split(new[] { "PatientId: " }, StringSplitOptions.None)[1];
            Console.WriteLine();

            // 2. Add a medical record
            Console.WriteLine("2. Adding medical record...");
            var medRecord = new MedicalRecord
            {
                Date = DateTime.UtcNow.AddDays(-30),
                ProviderId = "DR-001",
                ProviderName = "Dr. Smith",
                Facility = "General Hospital",
                DiagnosisCode = "J06.9",
                DiagnosisDescription = "Acute upper respiratory infection",
                TreatmentNotes = "Patient presented with sore throat and congestion. Prescribed rest and fluids.",
                Type = RecordType.Consultation,
                LabResults = new List<LabResult>()
            };

            var addRecordResponse = client.AddMedicalRecord(patientId, medRecord);
            Console.WriteLine($"   Result: {addRecordResponse.Message}");
            Console.WriteLine();

            // 3. Add medication
            Console.WriteLine("3. Adding medication...");
            var medication = new Medication
            {
                Name = "Amoxicillin",
                NDCCode = "0093-4150-01",
                Dosage = "500mg",
                Frequency = "Three times daily",
                Route = "Oral",
                PrescribedDate = DateTime.UtcNow.AddDays(-30),
                PrescribedBy = "Dr. Smith",
                IsActive = true
            };

            var addMedResponse = client.AddMedication(patientId, medication);
            Console.WriteLine($"   Result: {addMedResponse.Message}");
            Console.WriteLine();

            // 4. Search for the patient
            Console.WriteLine("4. Searching for patient...");
            var searchResponse = client.SearchPatient(new PatientSearchCriteria
            {
                LastName = "Doe"
            });
            Console.WriteLine($"   Result: {searchResponse.Message}");
            Console.WriteLine($"   Total Results: {searchResponse.TotalResults}");
            if (searchResponse.Patients != null)
            {
                foreach (var p in searchResponse.Patients)
                {
                    Console.WriteLine($"   - {p.PatientId}: {p.FirstName} {p.LastName}, DOB: {p.DateOfBirth:d}");
                    Console.WriteLine($"     Allergies: {p.Allergies?.Count ?? 0}");
                    Console.WriteLine($"     Medical Records: {p.MedicalHistory?.Count ?? 0}");
                    Console.WriteLine($"     Active Medications: {p.CurrentMedications?.Count ?? 0}");
                }
            }
            Console.WriteLine();

            // 5. Get clinical documents
            Console.WriteLine("5. Retrieving clinical documents...");
            var docResponse = client.GetClinicalDocuments(new ClinicalDocumentRequest
            {
                PatientId = patientId,
                RequestingProviderId = "DR-002",
                PurposeOfUse = "Treatment"
            });
            Console.WriteLine($"   Result: {docResponse.Message}");
            if (docResponse.Documents != null)
            {
                foreach (var doc in docResponse.Documents)
                {
                    Console.WriteLine($"   - Record: {doc.RecordId}, Type: {doc.Type}, Date: {doc.Date:d}");
                    Console.WriteLine($"     Diagnosis: [{doc.DiagnosisCode}] {doc.DiagnosisDescription}");
                    Console.WriteLine($"     Provider: {doc.ProviderName} at {doc.Facility}");
                }
            }
            Console.WriteLine();

            // 6. Submit CCD (Continuity of Care Document)
            Console.WriteLine("6. Submitting Continuity of Care Document...");
            var ccdRecord = new PatientRecord
            {
                PatientId = patientId,
                FirstName = "Jane",
                LastName = "Doe",
                MedicalHistory = new List<MedicalRecord>
                {
                    new MedicalRecord
                    {
                        Date = DateTime.UtcNow.AddDays(-7),
                        ProviderId = "DR-003",
                        ProviderName = "Dr. Johnson",
                        Facility = "Specialist Clinic",
                        DiagnosisCode = "R05.9",
                        DiagnosisDescription = "Persistent cough",
                        TreatmentNotes = "Follow-up for respiratory infection. Cough persists. Ordered chest X-ray.",
                        Type = RecordType.Consultation,
                        LabResults = new List<LabResult>()
                    }
                }
            };

            var ccdResponse = client.SubmitContinuityOfCareDocument(patientId, ccdRecord);
            Console.WriteLine($"   Result: {ccdResponse.Message}");
            Console.WriteLine();

            // Close the client channel
            ((IClientChannel)client).Close();
            factory.Close();

            Console.WriteLine("--- Demo Operations Completed Successfully ---");
            Console.WriteLine();

            // Print security configuration summary
            PrintSecuritySummary();
        }
        catch (FaultException<HealthcareFault> faultEx)
        {
            Console.WriteLine($"Healthcare Fault: [{faultEx.Detail.ErrorCode}] {faultEx.Detail.ErrorMessage}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Demo Error: {ex.Message}");
            if (ex.InnerException != null)
                Console.WriteLine($"Inner: {ex.InnerException.Message}");
        }
    }

    static void PrintSecuritySummary()
    {
